function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);

    // Helper function to check if a subarray can be sorted by cyclic shifts
    // A subarray can be sorted by cyclic shifts if and only if it is a permutation
    // of the elements it should be in the sorted array.
    // More accurately, if the elements of the subarray are exactly the elements
    // that occupy those positions in the fully sorted array.
    function canBeSortedCyclically(subArray, targetSlice) {
        if (subArray.length === 0) return true;

        // Check if the elements in subArray are a permutation of the elements in targetSlice
        const subArrayCounts = new Map();
        for (const x of subArray) {
            subArrayCounts.set(x, (subArrayCounts.get(x) || 0) + 1);
        }

        const targetSliceCounts = new Map();
        for (const x of targetSlice) {
            targetSliceCounts.set(x, (targetSliceCounts.get(x) || 0) + 1);
        }

        if (subArrayCounts.size !== targetSliceCounts.size) return false;

        for (const [val, count] of subArrayCounts) {
            if (targetSliceCounts.get(val) !== count) {
                return false;
            }
        }
        return true;
    }

    // Function to check if k is a valid sortable integer
    function isSortable(k) {
        if (k === 1) {
            // For k=1, each subarray has one element, which cannot be moved to achieve a sort unless already sorted
            // The problem statement implies that if the array is not fully sorted, k=1 fails.
            // Let's check the constraint from the example: Example 1, k=1 fails.
            // If nums is already sorted, k=1 technically satisfies the condition (vacuously true, or it's trivial).
            // However, based on the logic of "independently perform cyclic shifts", a single element array cannot be "moved" to change order.
            // If the array is already sorted, it's fine.
            if (nums.every((val, index) => val === sortedNums[index])) {
                return true; // Already sorted
            }
            return false;
        }

        // If k=n, there is one subarray, and any permutation can be sorted by cyclic shifts if it's a permutation of the target.
        if (k === n) {
            // Since the problem requires sorting the *entire* array, if k=n, the single subarray must be a permutation of the sorted array.
            // Since nums is a permutation of sortedNums, this is always true.
            // The condition is that it *can* be sorted. Any permutation of a set of elements can be sorted by cyclic shifts if k=n.
            // Wait, this is only true if the elements are unique or if the cyclic shift property covers all permutations.
            // A set of size k can only be sorted by cyclic shifts if it's already sorted OR if it's a cyclic shift of the sorted version.
            // For k=n, if nums is a permutation of sortedNums, we need to check if nums is a cyclic shift of sortedNums.

            // A simpler necessary and sufficient condition for a sequence P to be transformable to S by cyclic shifts is that
            // P must be a cyclic shift of S.

            // Check if nums is a cyclic shift of sortedNums
            const sortedString = sortedNums.join(',');
            const numsString = nums.join(',');

            const doubledSorted = sortedString + ',' + sortedString.slice(0, -1); // Append to check for wrap around
            return doubledSorted.includes(numsString);
        }


        // General case: k is a divisor of n.
        // The array is divided into n/k blocks of size k.
        // Let M = n/k be the number of blocks.

        const numBlocks = n / k;
        let isPossible = true;

        for (let i = 0; i < numBlocks; i++) {
            // Block i starts at index i*k and ends at (i+1)*k - 1

            // The actual subarray: nums[i*k ... (i+1)*k - 1]
            const actualSubarray = nums.slice(i * k, (i + 1) * k);

            // The target elements for this block: sortedNums[i*k ... (i+1)*k - 1]
            const targetSlice = sortedNums.slice(i * k, (i + 1) * k);

            // Condition 1: The elements within the block must be exactly the elements that belong there in the final sorted array.
            if (!canBeSortedCyclically(actualSubarray, targetSlice)) {
                isPossible = false;
                break;
            }

            // Condition 2: The blocks must be in the correct relative order *after* sorting internally.
            // Since we are sorting *each* block independently, the only way the whole array is sorted is if 
            // the smallest element of block i is less than or equal to the smallest element of block i+1.
            // AND, more strictly, the *sorted* block i must be less than or equal to the *sorted* block i+1.

            // Since canBeSortedCyclically ensures actualSubarray is a permutation of targetSlice, 
            // the sorted version of actualSubarray IS targetSlice.

            // We need to ensure that targetSlice_i <= targetSlice_{i+1} lexicographically.
            // Since targetSlice is already sorted by construction (it's a slice of sortedNums), 
            // this means we must ensure that the largest element of block i is <= the smallest element of block i+1.

            if (i < numBlocks - 1) {
                // Max of block i (which is the last element of targetSlice_i)
                const maxOfBlockI = targetSlice[k - 1]; 
                // Min of block i+1 (which is the first element of targetSlice_{i+1})
                const minOfBlockIPlus1 = targetSlice[k]; 

                // Since sortedNums is non-decreasing, maxOfBlockI <= minOfBlockIPlus1 is always true IF k divides n.
                // This check is redundant if canBeSortedCyclically passes for all blocks, because the blocks are derived from sortedNums.
                // The critical insight is that the ability to cyclically shift *within* a block only rearranges elements within that block; it cannot move an element from block i to block j.
                // Therefore, for the entire array to be sorted, the set of elements in block i MUST exactly match the set of elements that belong in the sorted block i.
            }
        }

        // Final check for k=n: If k=n, we checked the cyclic shift property above.
        if (k === n) {
            return false; // Already handled k=n case separately above for clarity, but if we reach here, k<n or k=n logic needs consolidation.
        }

        // The core requirement is that for every block i, the elements {nums[i*k]...nums[(i+1)*k-1]} must be exactly {sortedNums[i*k]...sortedNums[(i+1)*k-1]}.
        // This is captured by canBeSortedCyclically.
        return isPossible;
    }

    let sum = 0;
    for (let k = 1; k <= n; k++) {
        if (n % k === 0) {
            if (isSortable(k)) {
                sum += k;
            }
        }
    }

    return sum;
