fun solve(nums: Array<Long>): Long {
    val n = nums.size
    val sortedNums = nums.sortedArray()

    // Helper function to check if a subarray (actual) is a permutation of a target slice.
    fun canBeSortedCyclically(actual: LongArray, target: LongArray): Boolean {
        if (actual.size != target.size) return false
        if (actual.isEmpty()) return true

        val actualCounts = mutableMapOf<Long, Int>()
        for (x in actual) {
            actualCounts[x] = actualCounts.getOrDefault(x, 0) + 1
        }

        val targetCounts = mutableMapOf<Long, Int>()
        for (x in target) {
            targetCounts[x] = targetCounts.getOrDefault(x, 0) + 1
        }

        if (actualCounts.size != targetCounts.size) return false

        for ((valKey, count) in actualCounts) {
            if (targetCounts[valKey] != count) {
                return false
            }
        }
        return true
    }

    // Function to check if k is a valid sortable integer
    fun isSortable(k: Int): Boolean {
        if (k == 1) {
            // If k=1, each subarray is a single element. It can only be sorted if the array is already sorted.
            var alreadySorted = true
            for (i in 0 until n) {
                if (nums[i] != sortedNums[i]) {
                    alreadySorted = false
                    break
                }
            }
            return alreadySorted
        }

        // Case k=n: The single subarray must be a cyclic shift of the fully sorted array.
        if (k == n) {
            // Check if nums is a cyclic shift of sortedNums.
            // Create a doubled sequence of sortedNums to check for substrings.
            val sortedString = sortedNums.joinToString(",")
            val numsString = nums.joinToString(",")

            // To handle wrapping: double the sequence, removing the last element of the second copy
            // Example: [1, 2, 3] -> "1,2,3"
            // Double + wrap check: "1,2,3,1,2"
            val doubledSorted = sortedString + "," + sortedString.substring(0, sortedString.length - 1)

            return doubledSorted.contains(numsString)
        }

        // General case: k is a divisor of n, and 1 < k < n.
        val numBlocks = n / k

        // The necessary and sufficient condition is that for every block i, 
        // the elements in nums[i*k ... (i+1)*k - 1] must be exactly the elements 
        // that belong in the sorted block i, i.e., sortedNums[i*k ... (i+1)*k - 1].
        // This is because cyclic shifts only permute elements within the block.
        // If the required elements are not present, sorting is impossible.

        for (i in 0 until numBlocks) {
            val startIndex = i * k

            // 1. Extract the actual subarray from nums
            val actualSubarray = LongArray(k) { j -> nums[startIndex + j] }

            // 2. Extract the target slice from sortedNums
            val targetSlice = LongArray(k) { j -> sortedNums[startIndex + j] }

            // 3. Check if the counts match (i.e., is it a permutation)
            if (!canBeSortedCyclically(actualSubarray, targetSlice)) {
                return false
            }
        }

        // If all blocks contain the correct set of elements, and since the relative ordering 
        // of blocks in the sorted array is preserved by construction (they come from sortedNums),
        // the entire array can be sorted.
        return true
    }

    var sum: Long = 0
    for (k in 1..n) {
        if (n % k == 0) {
            if (isSortable(k)) {
                sum += k.toLong()
            }
        }
    }

    return sum
}
